						<input TYPE="reset" id="reset" class="Button btn btn-default" VALUE="Zur&uuml;cksetzen">				<INPUT TYPE="submit" class="Button btn btn-primary" id="validateButton" VALUE="Berechnung starten"  data-toggle="modal"    >		</div>	</div>	<a id="back-to-top" href="#" class="btn btn-primary btn-lg back-to-top" role="button" data-toggle="tooltip" data-placement="left"><span class="glyphicon glyphicon-chevron-up"></span></a>	<footer>		<div class="footer">			<p></p>			<p></p>			<p class="satzinno col-sm-offset-3">Qualitypool GmbH Sebastian Krüger Unternehmensberatung und Risikomanagement Dolziger Str. 51, 10247 Berlin</p>		</div>	</footer></div> <!--container--><!--Modal success --><div id="myModal" class="modal fade">	<div class="modal-dialog">		<div class="modal-content">			<div class="modal-header">				<button type="button" class="close" data-dismiss="modal" aria-hidden="true">&times;</button>				<h1>Berechnung wird durchgeführt.</h1>			</div>			<div class="modal-body">				Dies kann bis zu einer Minute dauern.						<div class="progress progress-striped active">					<div class="progress-bar" style="width: 80%;">						<span class="sr-only">80% Complete</span>					</div>				</div>			</div>		</div>	</div></div><!-- Modal for displaying the messages --><div class="modal fade" id="messageModal" tabindex="-1" role="dialog" aria-labelledby="Login" aria-hidden="true">	<div class="modal-dialog">		<div class="modal-content">			<div class="modal-header">				<button type="button" class="close" data-dismiss="modal" aria-label="Close">					<span aria-hidden="true">&times;</span>				</button>				<h5 class="modal-title">Fehler beim Absenden des Formulars</h5>			</div>			<div class="modal-body">				<div id="errors">Bitte überprüfen Sie Ihre Eingaben.</div>			</div>			<div class="modal-footer">				<button type="button" class="btn btn-default" data-dismiss="modal">Schliessen</button>			</div>		</div>	</div></div><style>	.datepicker{z-index:1151 !important;}</style><script type="text/javascript">	jQuery(document).ready(function() {		$('div.form-group input[rel=bsdatepicker]').each( function() { formatDate( this.name ) } );		 	 $('#VBEGINN')		.datepicker({			dateFormat: 'dd.mm.yy',			minDate: '+1',			maxDate: "+12m",			pickerPosition: "bottom-left"		})		.on('change.datepicker', function() {					var Datum 	= $('#VBEGINN').val();			var Laenge 	= Datum.length;			var m	 	= Datum.match( /\./ );			var m	 	= Datum.match( /\./ );			if ( m == null ){				if ( Laenge == 10 ) {										var mm 		= Datum.substring(0,2);					var tt 		= Datum.substring(3,5);					var jjjj 	= Datum.substring(6,10);										$("#VBEGINN").val( tt + '.' + mm + '.' + jjjj );									} else if ( Laenge == 8 ) {					var tt 		= Datum.substring(0,2);					var mm 		= Datum.substring(2,4);					var jjjj 	= Datum.substring(4,8);										$("#VBEGINN").val( tt + '.' + mm + '.' + jjjj );									}else if ( Laenge == 6 ) {					var tt 		= Datum.substring(0,2);					var mm 		= Datum.substring(2,4);					var jjjj 	= Datum.substring(4,6);										if ( jjjj < 20 ) {						var jahrhundert = 20;					} else {						var jahrhundert = 19;					}										$("#VBEGINN").val( tt + '.' + mm + '.' + jahrhundert + jjjj );				}			}					$('#inputForm').data('formValidation').enableFieldValidators( 'VBEGINN', true ).revalidateField('VBEGINN');	 });				$('#DATUM')			.datepicker({				dateFormat: 'dd.mm.yy',				maxDate: '-18y',				pickerPosition: "bottom-left"		})		.on('change.datepicker', function() {					var Datum 	= $('#DATUM').val();			var Laenge 	= Datum.length;			var m	 	= Datum.match( /\./ );			var m	 	= Datum.match( /\./ );			if ( m == null ){				if ( Laenge == 10 ) {										var mm 		= Datum.substring(0,2);					var tt 		= Datum.substring(3,5);					var jjjj 	= Datum.substring(6,10);										$("#DATUM").val( tt + '.' + mm + '.' + jjjj );									} else if ( Laenge == 8 ) {					var tt 		= Datum.substring(0,2);					var mm 		= Datum.substring(2,4);					var jjjj 	= Datum.substring(4,8);										$("#DATUM").val( tt + '.' + mm + '.' + jjjj );									}else if ( Laenge == 6 ) {					var tt 		= Datum.substring(0,2);					var mm 		= Datum.substring(2,4);					var jjjj 	= Datum.substring(4,6);										if ( jjjj < 20 ) {						var jahrhundert = 20;					} else {						var jahrhundert = 19;					}										$("#DATUM").val( tt + '.' + mm + '.' + jahrhundert + jjjj );				}							}						$('#inputForm').data('formValidation').enableFieldValidators( 'DATUM', true ).revalidateField('DATUM');	});		$('#inputForm')	.formValidation({		framework: 'bootstrap',		excluded: [':disabled'],		/*err: {			container: '#errors'		},*/		icon: {			valid: 'glyphicon glyphicon-ok',			invalid: 'glyphicon glyphicon-remove',			validating: 'glyphicon glyphicon-refresh'		},		fields: {			VBEGINN: {				validators: {                    notEmpty: {                        message: 'Bitte geben Sie das gewüsnchte Beginndatum der Versicherung an',                    },					callback: {						message: 'Der Vertrag kann frühestens morgen, und spätestens in einem Jahr beginnen',						callback: function(value, validator) {							var beginn = $('#VBEGINN').val();							formatDate( beginn );														$('#VBEGINN').val( beginn);							var a = moment(beginn, 'DD.MM.YYYY');							if (!a.isValid()) {                                return false;                            }							var b = moment().add(365, 'day');							var c = moment( 'a', 'DD.MM.YYYY');														return (b > a && a > c ); // zu frueh oder zu spaet!						}					},					//date: {					//		format: 'DD.MM.YYYY',					//		message: 'Das Datum ist nicht korrekt.'					//} 				}           			},			DATUM: {				validators: {                    notEmpty: {                        message: 'Bitte geben Sie das Geburtsdatum des Versicherungsnehmers ein',                    },                    callback: {						message: 'Der Antragsteller muss mindesten 18 Jahre alt sein',						callback: function(value, validator) {							var vndatum = $('#DATUM').val();							formatDate( vndatum );							$('#DATUM').val( vndatum);														var a = moment(vndatum, 'DD.MM.YYYY');							if (!a.isValid()) {                                return false;                            }                            							var b = moment().subtract(6570, 'day');							var c = moment( 'b', 'DD.MM.YYYY');							return ( b > a ); // fixmee !!						}					},					 date: {							format: 'DD.MM.YYYY',							message: 'Das Datum ist nicht korrekt.'					 }                }			},			tarifart: {				row: '.col-xs-10',				validators: {					notEmpty: {						message: 'Bitte wählen Sie eine Tarifart aus.'					}				}			}, 			deckungssumme: {				row: '.col-xs-10',				validators: {					notEmpty: {						message: 'Bitte wählen Sie die gewünschte Deckungssumme aus.'                    }				}			},			selbstbeteiligung: {				row: '.col-xs-10',				validators: {					notEmpty: {						message: 'Bitte wählen Sie die gewünschte Selbstbeteiligung aus.'                    }				}			},			plz: {				row: '.col-xs-10',				validators: {//					notEmpty: {//						message: 'Bitte geben Sie eine Postleitzahl Versicherungsnehmer ein'//					},					numeric: {						message: 'Die Postleitzahl darf nur Ziffern enthalten'                    },                    stringLength: {                        max: 5,                        min: 5,                        message: 'Die Postleitzahl muss 5-stellig sein'                    },                      					between: {						min: '01067',						max: '99998',						message: 'Die Postleitzahl muss zwischen 01067 und 99998 sein'					},				}			},			targru: {				row: '.col-xs-10',				enabled: true,				validators: {					notEmpty: {						message: 'Bitte wählen Sie die Tarifgruppe aus'                    },				}			},			ZAHLWEISE: {				row: '.col-xs-10',				enabled: true,				validators: {					notEmpty: {						message: 'Bitte wählen Sie die Zahlweise aus'                    },				}			},						diensteigenschaft: {				row: '.col-xs-10',				enabled: false,				validators: {					notEmpty: {						message: 'Bitte wählen Sie die Tätigkeitsbezeichnung aus.'                    }				}			},			vermittler_erstinformation: {				row: '.col-xs-10',				enabled: false,				validators: {					notEmpty: {						message: 'Bitte bestätigen Sie, dass Sie die Vermittlererstinformation heruntergeladen, sowie gelesen haben.'                    }				}			},			zugangsweg: {				row: '.col-xs-10',				enabled: false,				validators: {					notEmpty: {						message: 'Bitte wählen Sie den Zugangsweg aus.'                    }				}			},			taetigkeit: {				row: '.col-xs-10',				enabled: false,				validators: {					notEmpty: {						message: 'Bitte wählen Sie die Tätigkeit aus.'                    }				}			},					    taetigkeitMvp: {				enabled: false,				row: '.col-xs-10',				validators: {					notEmpty: {						message: 'Bitte wählen Sie die Tätigkeit aus.'                    }				}			}  		}	 })		.on('err.form.fv', function(e) {			// Show the message modal			$('#messageModal').modal('show');		})		.on('success.form.fv', function(e) {			// Show the message modal			 $('#myModal').modal('show');		})	         // Called when a field is invalid        .on('err.field.fv', function(e, data) {            // data.element --> The field element            var $tabPane = data.element.parents('.tab-pane'),                tabId    = $tabPane.attr('id');            $('a[href="#' + tabId + '"][data-toggle="tab"]')                .parent()                .find('span')                .addClass('label-danger');        })        // Called when a field is valid        .on('success.field.fv', function(e, data) {            // data.fv      --> The FormValidation instance            // data.element --> The field element            var $tabPane = data.element.parents('.tab-pane'),                tabId    = $tabPane.attr('id'),                $icon    = $('a[href="#' + tabId + '"][data-toggle="tab"]')                            .parent()                            .find('span')                            .removeClass('label-danger');            // Check if all fields in tab are valid            var isValidTab = data.fv.isValidContainer($tabPane);            if (isValidTab !== null) {                $icon.addClass(isValidTab ? 'fa-check' : 'label-danger');            }        });	  });  	function tarifgruppe() {		var targru= $('#targru').val();				if ( targru == 1 ) {			//console.log('Test 0');			$('#beamte').removeClass('hide');			$('#beamte').removeClass('disabled');			$('#inputForm').data('formValidation').enableFieldValidators( 'diensteigenschaft', true ).revalidateField('diensteigenschaft');			$('#inputForm').data('formValidation').enableFieldValidators( 'zugangsweg', true ).revalidateField('zugangsweg');			//$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeit', true ).revalidateField('taetigkeit');			//$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeitMvp', true ).revalidateField('taetigkeit');		} else {			$('#beamte').addClass('hide');			$('#inputForm').data('formValidation').enableFieldValidators( 'diensteigenschaft', false ).revalidateField('diensteigenschaft');			$('#inputForm').data('formValidation').enableFieldValidators( 'zugangsweg', false ).revalidateField('zugangsweg');			$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeit', false ).revalidateField('taetigkeit');			$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeitMvp', false ).revalidateField('taetigkeit');						$('#fragen_zu_diensthaft').removeClass('show').addClass('hide');			$('#fragen_zu_diensthaftMVP').removeClass('show').addClass('hide');			$('#beamte').addClass('disabled');		}	}	function diensthaft_einschluss() {		var targru= $('#targru').val();			 if (jQuery('#diensthaftpflicht').is(":checked") && targru == 1) {			$('#fragen_zu_diensthaft').removeClass('hide');			$('#fragen_zu_diensthaft').removeClass('disabled');			//console.log('Test 1');			$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeit', true ).revalidateField('taetigkeit');	     } else {			// console.log('Test 2');			$('#fragen_zu_diensthaft').removeClass('show').addClass('hide');			$('#fragen_zu_diensthaft').removeClass('show').addClass('disabled');			$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeit', false ).revalidateField('taetigkeit');		 }	}	 function einschluss_mvp() {			var dienshaftpflicht_mvp = jQuery("#tarifart").val();						if (dienshaftpflicht_mvp != 'se' && dienshaftpflicht_mvp != 'sk') {				jQuery("#diensthaft_mvp").attr('style', 'display:block'); 			} else {				jQuery("#diensthaft_mvp").attr('style', 'display:none');			}	}		function diensthaft_einschlussMVP() {			var targru= $('#targru').val();		if (jQuery('#diensthaftpflichtMvp').is(":checked") && targru == 1) {			$('#fragen_zu_diensthaftMVP').removeClass('hide');			$('#fragen_zu_diensthaftMVP').removeClass('disabled');			$('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeitMvp', true ).revalidateField('taetigkeitMvp');		 } else {			 $('#fragen_zu_diensthaftMVP').removeClass('show').addClass('hide');			 $('#fragen_zu_diensthaftMVP').removeClass('show').addClass('disabled');			 $('#inputForm').data('formValidation').enableFieldValidators( 'taetigkeitMvp', false ).revalidateField('taetigkeitMvp');			 		 }	}</script><script type = "text/javascript">		$('#reset').click(function() {				//console.log('test');				$('#inputForm').formValidation('updateStatus','VBEGINN','NOT_VALIDATED')		       .formValidation('updateStatus','VBEGINN');		       		       		$('#inputForm').formValidation('updateStatus','DATUM','NOT_VALIDATED')		       .formValidation('updateStatus','DATUM');		       		$('#inputForm').formValidation('updateStatus','tarifart','NOT_VALIDATED')		       .formValidation('updateStatus','tarifart');		       		$('#inputForm').formValidation('updateStatus','deckungssumme','NOT_VALIDATED')		       .formValidation('updateStatus','deckungssumme');		       		$('#inputForm').formValidation('updateStatus','selbstbeteiligung','NOT_VALIDATED')		       .formValidation('updateStatus','selbstbeteiligung');		       	});	</script></form></body></html>